import React from 'react';

const Home = () => {
  return (
    <main>
      <nav className="navbar">
        <a href="/" className="logo">
          Handy<span>Near</span>
        </a>
        <ul className="nav-links">
          <li><a href="/">Home</a></li>
          <li><a href="/browse">Find a Handyman</a></li>
          <li><a href="/how-it-works">How It Works</a></li>
          <li><a href="/contact">Post a Job</a></li>
        </ul>
        <button className="hamburger" id="hamburger">&#9776;</button>
      </nav>

      <section className="hero">
        <h1>Welcome to HandyNear</h1>
        <p>Find trusted local handymen near you.</p>
      </section>
    </main>
  );
};

export default Home;
